                    debuffConfig: { debuffType: 'socialPenalty', effects: [{ id: 'favor_owed', name: 'Favor Owed', description: 'The debt will be collected. The GM decides when.', statusEffect: { penaltyType: 'narrative_debt' } }], targetRestriction: 'self' },
